import { Link } from 'react-router-dom';
import './ActivityItem.css';
import { deleteDoc, doc } from 'firebase/firestore';
import { db } from '../../services/firebase';
import { useLanguage } from '../../context/LanguageContext';

interface Activity {
  id: string;
  title: string;
  location: string;
  date: string;
  maxPeople: number;
  people: string[];
  creatorId: string;
}

interface ActivityItemProps {
  activity: Activity;
  currentUserId: string;
  onDelete: (id: string) => void;
}

export default function ActivityItem({ activity, currentUserId, onDelete }: ActivityItemProps) {
  const { t } = useLanguage();
  const now = new Date();
  const eventDate = new Date(activity.date);
  
  let statusColor = 'gray';
  if (now > eventDate) statusColor = 'red';
  else if (now < new Date(eventDate.getTime() - 3600000)) statusColor = 'orange';
  else statusColor = 'green';

  const canDelete = activity.creatorId === currentUserId;

  return (
    <div className="activity-item">
      <div className="activity-header">
        <h3>{activity.title}</h3>
        {canDelete && (
          <button 
            onClick={() => onDelete(activity.id)}
            className="delete-btn"
          >
            {t.delete}
          </button>
        )}
      </div>
      <div className="activity-meta">
        <span>📍 {activity.location}</span>
        <span>📅 {eventDate.toLocaleString()}</span>
        <span>👥 {activity.people.length}/{activity.maxPeople}</span>
        <span 
          className="status-indicator" 
          style={{ backgroundColor: statusColor }}
          title={statusColor === 'red' ? t.finished : 
                 statusColor === 'orange' ? t.upcoming : t.active}
        />
      </div>
      <Link to={`/activity/${activity.id}`} className="details-btn">
        {t.viewDetails}
      </Link>
    </div>
  );
}
